-- Name: add_column_if_not_exists(text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_column_if_not_exists(_table_name text, _column_name text, _column_type text, _default_value text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT column_exists(_table_name, _column_name) THEN
        IF _default_value IS NULL THEN
            EXECUTE format('ALTER TABLE public.%I ADD COLUMN %I %s', 
                         _table_name, _column_name, _column_type);
        ELSE
            EXECUTE format('ALTER TABLE public.%I ADD COLUMN %I %s DEFAULT %s', 
                         _table_name, _column_name, _column_type, _default_value);
        END IF;
    END IF;
END;
$$;


ALTER FUNCTION public.add_column_if_not_exists(_table_name text, _column_name text, _column_type text, _default_value text) OWNER TO postgres;

--
-- Name: add_fk_constraint_if_not_exists(text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_fk_constraint_if_not_exists(_table_name text, _column_name text, _referenced_table text, _referenced_column text DEFAULT 'id'::text, _constraint_name text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    _cons_name text;
BEGIN
    IF _constraint_name IS NULL THEN
        _cons_name := format('fk_%s_%s', _table_name, _column_name);
    ELSE
        _cons_name := _constraint_name;
    END IF;
    
    IF NOT EXISTS (
        SELECT 1
        FROM information_schema.table_constraints tc
        JOIN information_schema.constraint_column_usage ccu ON tc.constraint_name = ccu.constraint_name
        WHERE tc.constraint_type = 'FOREIGN KEY'
        AND tc.table_schema = 'public'
        AND tc.table_name = _table_name
        AND ccu.column_name = _referenced_column
        AND ccu.table_name = _referenced_table
    ) THEN
        EXECUTE format('ALTER TABLE public.%I ADD CONSTRAINT %I FOREIGN KEY (%I) REFERENCES public.%I(%I)',
                     _table_name, _cons_name, _column_name, _referenced_table, _referenced_column);
    END IF;
END;
$$;


ALTER FUNCTION public.add_fk_constraint_if_not_exists(_table_name text, _column_name text, _referenced_table text, _referenced_column text, _constraint_name text) OWNER TO postgres;

