--
-- Name: admin_set_user_role(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.admin_set_user_role(user_id uuid, new_role text) RETURNS json
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_catalog'
    AS $$
BEGIN
  -- Update the user's role in the profiles table
  UPDATE profiles
  SET role = new_role -- Ensure new_role is of type TEXT
  WHERE id = user_id;
  
  RETURN json_build_object(
    'success', true,
    'message', 'User role updated to ' || new_role
  );
EXCEPTION
  WHEN OTHERS THEN
    RETURN json_build_object(
      'success', false,
      'message', 'Error: ' || SQLERRM
    );
END;
$$;


