--
-- Name: auto_log_changes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.auto_log_changes() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Log based on operation type
    IF TG_OP = 'INSERT' THEN
        PERFORM log_activity(
            TG_TABLE_NAME || ' Created',
            'create',
            TG_TABLE_NAME,
            COALESCE(NEW.id::text, NEW.name, 'unknown'),
            'New ' || TG_TABLE_NAME || ' record created',
            'success',
            'low'
        );
        RETURN NEW;
    ELSIF TG_OP = 'UPDATE' THEN
        PERFORM log_activity(
            TG_TABLE_NAME || ' Updated',
            'update',
            TG_TABLE_NAME,
            COALESCE(NEW.id::text, NEW.name, 'unknown'),
            'Record updated in ' || TG_TABLE_NAME,
            'success',
            'low'
        );
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        PERFORM log_activity(
            TG_TABLE_NAME || ' Deleted',
            'delete',
            TG_TABLE_NAME,
            COALESCE(OLD.id::text, OLD.name, 'unknown'),
            'Record deleted from ' || TG_TABLE_NAME,
            'success',
            'medium'
        );
        RETURN OLD;
    END IF;
    
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.auto_log_changes() OWNER TO postgres;

