CREATE FUNCTION public.column_exists(_table_name text, _column_name text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    _exists boolean;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = 'public'
        AND table_name = _table_name
        AND column_name = _column_name
    ) INTO _exists;
    
    RETURN _exists;
END;
$$;


