--
-- Name: generate_user_gate_pass_on_approval(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.generate_user_gate_pass_on_approval() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  user_gate_pass_id TEXT;
  entry_code TEXT;
  qr_code_data TEXT;
  unit_block TEXT;
  unit_number TEXT;
  society_name TEXT;
BEGIN
  -- Only trigger when status changes to 'approved'
  IF NEW.status = 'approved' AND (OLD.status IS NULL OR OLD.status != 'approved') THEN
    
    -- Get unit information
    SELECT u.block, u.number INTO unit_block, unit_number
    FROM units u
    WHERE u.id = NEW.unit_id;
    
    -- Get society name
    SELECT s.name INTO society_name
    FROM societies s
    WHERE s.id = NEW.community_id;
    
    -- Generate unique user gate pass ID
    user_gate_pass_id := 'UP-' || EXTRACT(EPOCH FROM NOW())::TEXT || '-' || substr(md5(random()::text), 1, 9);
    
    -- Generate entry code from user gate pass ID (last 8 characters)
    entry_code := upper(substr(user_gate_pass_id, -8));
    
    -- Generate QR code data with unit and society information
    qr_code_data := json_build_object(
      'id', user_gate_pass_id,
      'name', (SELECT full_name FROM profiles WHERE id = NEW.user_id),
      'email', (SELECT email FROM profiles WHERE id = NEW.user_id),
      'society_id', NEW.community_id,
      'unit_id', NEW.unit_id,
      'unit_block', unit_block,
      'unit_number', unit_number,
      'society_name', society_name,
      'type', 'user_gate_pass',
      'entry_code', entry_code,
      'created_at', NOW()::TEXT,
      'expires_at', NULL
    )::TEXT;
    
    -- Update user profile with QR code and entry code
    UPDATE profiles 
    SET 
      qr_code_data = qr_code_data,
      entry_code = entry_code
    WHERE id = NEW.user_id;
    
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.generate_user_gate_pass_on_approval() OWNER TO postgres;

--
-- Name: get_activity_logs_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_activity_logs_stats() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    total_count INTEGER;
    today_count INTEGER;
    failed_count INTEGER;
    critical_count INTEGER;
    action_type_counts json;
    status_counts json;
    result json;
    
    -- For date calculation
    start_of_day TIMESTAMP;
    end_of_day TIMESTAMP;
BEGIN
    -- Calculate date range for today
    start_of_day := date_trunc('day', now());
    end_of_day := start_of_day + interval '1 day';
    
    -- Get total count
    SELECT COUNT(*) INTO total_count FROM activity_logs;
    
    -- Get today's count
    SELECT COUNT(*) INTO today_count FROM activity_logs 
    WHERE timestamp >= start_of_day AND timestamp < end_of_day;
    
    -- Get failed count
    SELECT COUNT(*) INTO failed_count FROM activity_logs WHERE status = 'failed';
    
    -- Get critical count
    SELECT COUNT(*) INTO critical_count FROM activity_logs WHERE severity = 'critical';
    
    -- Get action type distribution
    SELECT json_object_agg(action_type, count) INTO action_type_counts
    FROM (
        SELECT action_type, COUNT(*) as count 
        FROM activity_logs 
        GROUP BY action_type
    ) as action_types;
    
    -- Get status distribution
    SELECT json_object_agg(status, count) INTO status_counts
    FROM (
        SELECT status, COUNT(*) as count 
        FROM activity_logs 
        GROUP BY status
    ) as statuses;
    
    -- Build result JSON
    SELECT json_build_object(
        'total', total_count,
        'today', today_count,
        'failed', failed_count,
        'critical', critical_count,
        'byActionType', COALESCE(action_type_counts, '{}'::json),
        'byStatus', COALESCE(status_counts, '{}'::json)
    ) INTO result;
    
    RETURN result;
END;
$$;


ALTER FUNCTION public.get_activity_logs_stats() OWNER TO postgres;

