-- Name: FUNCTION get_activity_logs_stats(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_activity_logs_stats() IS 'Get activity log statistics bypassing RLS for any authenticated user.';


--
-- Name: get_admin_unread_notifications(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_unread_notifications(admin_user_id uuid) RETURNS TABLE(notification_id uuid, title text, body text, notification_type text, priority text, created_at timestamp with time zone, reference_id uuid, action_url text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        n.id,
        n.title,
        n.body,
        n.notification_type,
        n.priority,
        n.created_at,
        n.reference_id,
        n.action_url
    FROM notifications n
    WHERE n.user_id = admin_user_id
    AND n.is_read = false
    ORDER BY 
        CASE 
            WHEN n.priority = 'urgent' THEN 1
            WHEN n.priority = 'high' THEN 2
            WHEN n.priority = 'medium' THEN 3
            ELSE 4
        END,
        n.created_at DESC;
END;
$$;


ALTER FUNCTION public.get_admin_unread_notifications(admin_user_id uuid) OWNER TO postgres;

