--
-- Name: get_complaint_comments_with_profiles(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_complaint_comments_with_profiles(complaint_uuid uuid) RETURNS TABLE(id uuid, complaint_id uuid, comment text, created_by uuid, created_at timestamp with time zone, created_by_profile jsonb)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    cc.id,
    cc.complaint_id,
    cc.comment,
    cc.created_by,
    cc.created_at,
    jsonb_build_object(
      'id', p.id,
      'first_name', p.first_name,
      'last_name', p.last_name,
      'avatar_url', p.avatar_url,
      'email', p.email,
      'role', p.role,
      'unit_id', p.unit_id,
      'units', jsonb_build_object(
        'id', u.id,
        'block', u.block,
        'number', u.number,
        'unit_number', u.unit_number
      )
    ) as created_by_profile
  FROM public.complaint_comments cc
  LEFT JOIN public.profiles p ON cc.created_by = p.user_id
  LEFT JOIN public.units u ON p.unit_id = u.id
  WHERE cc.complaint_id = complaint_uuid
  ORDER BY cc.created_at ASC;
END;
$$;


ALTER FUNCTION public.get_complaint_comments_with_profiles(complaint_uuid uuid) OWNER TO postgres;

