--
-- Name: get_notification_system_status(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_notification_system_status() RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    result JSONB;
    pending_requests INTEGER;
    total_notifications INTEGER;
    pending_emails INTEGER;
    pending_sms INTEGER;
    sent_emails INTEGER;
    sent_sms INTEGER;
BEGIN
    -- Count pending join requests
    SELECT COUNT(*) INTO pending_requests
    FROM join_requests 
    WHERE status IN ('pending', 'pending_manual_review');
    
    -- Count total notifications
    SELECT COUNT(*) INTO total_notifications
    FROM notifications 
    WHERE notification_type IN ('join_request', 'join_request_manual');
    
    -- Count email queue status
    SELECT COUNT(*) INTO pending_emails
    FROM join_request_email_queue 
    WHERE status = 'pending';
    
    SELECT COUNT(*) INTO sent_emails
    FROM join_request_email_queue 
    WHERE status = 'sent';
    
    -- Count SMS queue status
    SELECT COUNT(*) INTO pending_sms
    FROM join_request_sms_queue 
    WHERE status = 'pending';
    
    SELECT COUNT(*) INTO sent_sms
    FROM join_request_sms_queue 
    WHERE status = 'sent';
    
    result := json_build_object(
        'system_status', 'active',
        'join_requests', json_build_object(
            'pending', pending_requests
        ),
        'notifications', json_build_object(
            'in_app_total', total_notifications,
            'emails', json_build_object(
                'pending', pending_emails,
                'sent', sent_emails
            ),
            'sms', json_build_object(
                'pending', pending_sms,
                'sent', sent_sms
            )
        ),
        'last_updated', NOW()
    );
    
    RETURN result;
END;
$$;


ALTER FUNCTION public.get_notification_system_status() OWNER TO postgres;

