--
-- Name: handle_new_auth_user(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.handle_new_auth_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  if tg_op = 'INSERT' then
    insert into public.users (
      id, email, first_name, last_name, phone, phone_number, role, password, created_at
    ) values (
      new.id,
      new.email,
      coalesce((new.raw_user_meta_data->>'first_name')::text, ''),
      coalesce((new.raw_user_meta_data->>'last_name')::text, ''),
      nullif((new.raw_user_meta_data->>'phone')::text, ''),
      nullif((new.raw_user_meta_data->>'phone')::text, ''),
      coalesce((new.raw_user_meta_data->>'role')::text, 'guard'),
      'auth_managed',
      now()
    )
    on conflict (id) do nothing;
  end if;
  return new;
end;
$$;


ALTER FUNCTION public.handle_new_auth_user() OWNER TO postgres;

--
-- Name: increment_notice_likes(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.increment_notice_likes(notice_id uuid) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE notices 
  SET likes_count = likes_count + 1,
      updated_at = NOW()
  WHERE id = notice_id;
END;
$$;


ALTER FUNCTION public.increment_notice_likes(notice_id uuid) OWNER TO postgres;

--
-- Name: increment_comment_likes(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.increment_comment_likes(comment_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    SET row_security TO 'off'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM public.comments c
    WHERE c.id = comment_id
  ) THEN
    RAISE EXCEPTION 'COMMENT_NOT_FOUND' USING ERRCODE = 'P0002';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.comments c
    JOIN public.notices n ON n.id = c.notice_id
    WHERE c.id = comment_id
      AND public.can_access_community(n.community_id)
  ) THEN
    RAISE EXCEPTION 'COMMENT_SCOPE_VIOLATION' USING ERRCODE = '42501';
  END IF;

  UPDATE public.comments
  SET likes_count = COALESCE(likes_count, 0) + 1,
      updated_at = NOW()
  WHERE id = comment_id;
END;
$$;


ALTER FUNCTION public.increment_comment_likes(comment_id uuid) OWNER TO postgres;

