--
-- Name: log_activity(character varying, character varying, character varying, character varying, text, character varying, character varying, jsonb, inet, text, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_activity(p_action character varying, p_action_type character varying, p_resource character varying, p_resource_id character varying DEFAULT NULL::character varying, p_details text DEFAULT ''::text, p_status character varying DEFAULT 'success'::character varying, p_severity character varying DEFAULT 'low'::character varying, p_metadata jsonb DEFAULT NULL::jsonb, p_ip_address inet DEFAULT NULL::inet, p_user_agent text DEFAULT NULL::text, p_location character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    activity_id UUID;
    current_user_id UUID;
    current_user_name VARCHAR(255);
    current_user_role VARCHAR(100);
BEGIN
    -- Get current user context
    current_user_id := auth.uid();
    
    -- Get user name and role from profiles or auth.users
    SELECT 
        COALESCE(p.first_name || ' ' || p.last_name, u.email),
        COALESCE(p.role, 'Unknown')
    INTO current_user_name, current_user_role
    FROM auth.users u
    LEFT JOIN public.profiles p ON u.id = p.id
    WHERE u.id = current_user_id;
    
    -- Default to system if no user context
    IF current_user_id IS NULL THEN
        current_user_name := 'System';
        current_user_role := 'System';
    END IF;
    
    -- Insert activity log
    INSERT INTO public.activity_logs (
        user_id, user_name, user_role,
        action, action_type, resource, resource_id,
        details, status, severity, metadata,
        ip_address, user_agent, location
    ) VALUES (
        current_user_id, current_user_name, current_user_role,
        p_action, p_action_type, p_resource, p_resource_id,
        p_details, p_status, p_severity, p_metadata,
        COALESCE(p_ip_address, inet_client_addr()),
        p_user_agent, p_location
    ) RETURNING id INTO activity_id;
    
    RETURN activity_id;
END;
$$;


ALTER FUNCTION public.log_activity(p_action character varying, p_action_type character varying, p_resource character varying, p_resource_id character varying, p_details text, p_status character varying, p_severity character varying, p_metadata jsonb, p_ip_address inet, p_user_agent text, p_location character varying) OWNER TO postgres;

