--
-- Name: notify_admins_new_join_request(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.notify_admins_new_join_request() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    admin_record RECORD;
    user_name TEXT;
    community_name TEXT;
    unit_info TEXT;
    email_subject TEXT;
    email_body TEXT;
    sms_message TEXT;
BEGIN
    -- Get user information from profiles table
    SELECT 
        CONCAT(first_name, ' ', last_name),
        COALESCE(NEW.community_name, (SELECT name FROM communities WHERE id = NEW.community_id))
    INTO user_name, community_name
    FROM profiles 
    WHERE id = NEW.user_id;
    
    -- Build unit information
    IF NEW.is_manual_entry THEN
        unit_info := NEW.manual_unit_info;
    ELSE
        SELECT CONCAT(block, '-', number) 
        INTO unit_info
        FROM units 
        WHERE id = NEW.unit_id;
    END IF;
    
    -- Build email content
    email_subject := 'New Join Request - ' || community_name;
    
    IF NEW.is_manual_entry THEN
        email_body := 'Dear Admin,

A new join request has been submitted for manual review:

Resident: ' || user_name || '
Community: ' || community_name || ' (Manual Entry)
Unit: ' || unit_info || '
Comments: ' || COALESCE(NEW.comments, 'None') || '

This is a manual entry request for a community that may not be in our system yet. Please review this request promptly.

Login to the admin portal to approve or reject this request.

Thank you,
Casa Nirvana Management System';
        
        sms_message := 'URGENT: Manual join request from ' || user_name || ' for ' || community_name || '. Please check admin portal.';
    ELSE
        email_body := 'Dear Admin,

A new join request has been submitted:

Resident: ' || user_name || '
Community: ' || community_name || '
Unit: ' || unit_info || '
Comments: ' || COALESCE(NEW.comments, 'None') || '

Please login to the admin portal to review and approve or reject this request.

Thank you,
Casa Nirvana Management System';
        
        sms_message := 'New join request from ' || user_name || ' for ' || community_name || '. Please check your admin portal.';
    END IF;
    
    -- Queue notifications for community admins
    IF NEW.community_id IS NOT NULL THEN
        -- Normal join request - get admins from communities table
        FOR admin_record IN 
            SELECT p.email, p.first_name, p.last_name, p.phone
            FROM profiles p
            JOIN communities c ON p.id = ANY(c.admins)
            WHERE c.id = NEW.community_id 
            AND p.email IS NOT NULL
        LOOP
            -- Queue email notification
            INSERT INTO join_request_email_queue (
                recipient_email,
                recipient_name,
                subject,
                body,
                join_request_id
            ) VALUES (
                admin_record.email,
                CONCAT(admin_record.first_name, ' ', admin_record.last_name),
                email_subject,
                email_body,
                NEW.id
            );
            
            -- Queue SMS notification if phone number exists
            IF admin_record.phone IS NOT NULL THEN
                INSERT INTO join_request_sms_queue (
                    recipient_phone,
                    recipient_name,
                    message,
                    join_request_id
                ) VALUES (
                    admin_record.phone,
                    CONCAT(admin_record.first_name, ' ', admin_record.last_name),
                    sms_message,
                    NEW.id
                );
            END IF;
        END LOOP;
    ELSE
        -- Manual entry - notify all admins from profiles table
        FOR admin_record IN 
            SELECT email, first_name, last_name, phone
            FROM profiles 
            WHERE role = 'admin' 
            AND email IS NOT NULL
        LOOP
            -- Queue email notification
            INSERT INTO join_request_email_queue (
                recipient_email,
                recipient_name,
                subject,
                body,
                join_request_id
            ) VALUES (
                admin_record.email,
                CONCAT(admin_record.first_name, ' ', admin_record.last_name),
                email_subject,
                email_body,
                NEW.id
            );
            
            -- Queue SMS notification if phone number exists
            IF admin_record.phone IS NOT NULL THEN
                INSERT INTO join_request_sms_queue (
                    recipient_phone,
                    recipient_name,
                    message,
                    join_request_id
                ) VALUES (
                    admin_record.phone,
                    CONCAT(admin_record.first_name, ' ', admin_record.last_name),
                    sms_message,
                    NEW.id
                );
            END IF;
        END LOOP;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.notify_admins_new_join_request() OWNER TO postgres;

