--
-- Name: process_pending_notifications(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.process_pending_notifications() RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    emails_processed INTEGER := 0;
    sms_processed INTEGER := 0;
    result JSONB;
BEGIN
    -- Update pending emails to sent (simulating successful sending)
    UPDATE join_request_email_queue 
    SET status = 'sent', sent_at = NOW()
    WHERE status = 'pending';
    
    GET DIAGNOSTICS emails_processed = ROW_COUNT;
    
    -- Update pending SMS to sent (simulating successful sending)
    UPDATE join_request_sms_queue 
    SET status = 'sent', sent_at = NOW()
    WHERE status = 'pending';
    
    GET DIAGNOSTICS sms_processed = ROW_COUNT;
    
    result := json_build_object(
        'success', true,
        'emails_sent', emails_processed,
        'sms_sent', sms_processed,
        'processed_at', NOW()
    );
    
    RETURN result;
END;
$$;


