    END IF;
    
    -- Queue notifications for community admins
    IF NEW.community_id IS NOT NULL THEN
        -- Normal join request - get admins from societies table
        -- NOTE: societies.admins array should also reference profiles, not users
        FOR admin_record IN 
            SELECT p.email, p.first_name, p.last_name, p.phone
            FROM profiles p
            JOIN societies s ON p.id = ANY(s.admins)
            WHERE s.id = NEW.community_id 
