                    CONCAT(admin_record.first_name, ' ', admin_record.last_name),
                    sms_message,
                    NEW.id
                );
            END IF;
        END LOOP;
    ELSE
        -- Manual entry - notify all admins from profiles table
        FOR admin_record IN 
            SELECT email, first_name, last_name, phone
            FROM profiles 
            WHERE role = 'admin' 
            AND email IS NOT NULL
        LOOP
            -- Queue email notification
            INSERT INTO join_request_email_queue (
                recipient_email,
                recipient_name,
                subject,
                body,
                join_request_id
            ) VALUES (
