--
-- Name: send_join_request_approval_notification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.send_join_request_approval_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    user_profile RECORD;
    community_info RECORD;
    unit_info RECORD;
    notification_title TEXT;
    notification_body TEXT;
BEGIN
    -- Only proceed if status changed to 'approved'
    IF NEW.status = 'approved' AND (OLD.status IS NULL OR OLD.status != 'approved') THEN
        
        -- Get user profile info
        SELECT p.*, u.email 
        INTO user_profile
        FROM profiles p
        JOIN auth.users u ON p.user_id = u.id
        WHERE p.id = NEW.user_id;
        
        -- Get community and unit info for regular requests
        IF NEW.community_id IS NOT NULL THEN
            SELECT s.name as society_name
            INTO community_info
            FROM societies s
            WHERE s.id = NEW.community_id;
            
            IF NEW.unit_id IS NOT NULL THEN
                SELECT u.block, u.number
                INTO unit_info
                FROM units u
                WHERE u.id = NEW.unit_id;
            END IF;
        END IF;
        
        -- Prepare notification content
        IF NEW.is_manual_entry = true THEN
            notification_title := 'Join Request Approved! 🎉';
            notification_body := format('Congratulations! Your request to join %s has been approved. Welcome to the community!', NEW.community_name);
        ELSE
            notification_title := 'Join Request Approved! 🎉';
            IF unit_info.block IS NOT NULL AND unit_info.number IS NOT NULL THEN
                notification_body := format('Congratulations! Your request for unit %s-%s in %s has been approved. Welcome to the community!', 
                    unit_info.block, unit_info.number, community_info.society_name);
            ELSE
                notification_body := format('Congratulations! Your request to join %s has been approved. Welcome to the community!', 
                    community_info.society_name);
            END IF;
        END IF;
        
        -- Insert notification
        INSERT INTO notifications (
            user_id,
            title,
            body,
            notification_type,
            reference_id,
            priority,
            is_read
        ) VALUES (
            NEW.user_id,
            notification_title,
            notification_body,
            'join_request_approved',
            NEW.id,
            'high',
            false
        );
        
        -- Update user profile with society and unit info (for approved regular requests)
        IF NEW.community_id IS NOT NULL AND NEW.unit_id IS NOT NULL THEN
            UPDATE profiles 
            SET 
                society_id = NEW.community_id,
                unit_id = NEW.unit_id,
                role = 'resident',
                status = 'active'
            WHERE id = NEW.user_id;
            
            -- Mark unit as occupied
            UPDATE units 
            SET status = 'occupied' 
            WHERE id = NEW.unit_id;
        END IF;
        
        RAISE LOG 'Join request approval notification sent for user_id: %', NEW.user_id;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.send_join_request_approval_notification() OWNER TO postgres;

