--

CREATE FUNCTION public.table_exists(_table_name text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    _exists boolean;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM information_schema.tables
        WHERE table_schema = 'public'
        AND table_name = _table_name
    ) INTO _exists;
    
    RETURN _exists;
END;
$$;


