--
-- Name: update_group_member_count(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_group_member_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Handle INSERT
    IF TG_OP = 'INSERT' THEN
        UPDATE public.user_groups 
        SET member_count = (
            SELECT COUNT(*) 
            FROM public.group_members 
            WHERE group_id = NEW.group_id AND is_active = true
        )
        WHERE id = NEW.group_id;
        RETURN NEW;
    END IF;
    
    -- Handle UPDATE
    IF TG_OP = 'UPDATE' THEN
        -- Update count for both old and new group if group_id changed
        UPDATE public.user_groups 
        SET member_count = (
            SELECT COUNT(*) 
            FROM public.group_members 
            WHERE group_id = NEW.group_id AND is_active = true
        )
        WHERE id = NEW.group_id;
        
        IF OLD.group_id != NEW.group_id THEN
            UPDATE public.user_groups 
            SET member_count = (
                SELECT COUNT(*) 
                FROM public.group_members 
                WHERE group_id = OLD.group_id AND is_active = true
            )
            WHERE id = OLD.group_id;
        END IF;
        RETURN NEW;
    END IF;
    
    -- Handle DELETE
    IF TG_OP = 'DELETE' THEN
        UPDATE public.user_groups 
        SET member_count = (
            SELECT COUNT(*) 
            FROM public.group_members 
            WHERE group_id = OLD.group_id AND is_active = true
        )
        WHERE id = OLD.group_id;
        RETURN OLD;
    END IF;
    
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.update_group_member_count() OWNER TO postgres;

--
-- Name: update_guard_display_name(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_guard_display_name() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Set display_name based on available name fields
  NEW.display_name = COALESCE(
    -- Prioritize first_name + last_name combination if both exist
    CASE WHEN (NEW.first_name IS NOT NULL AND NEW.last_name IS NOT NULL AND NEW.first_name != '' AND NEW.last_name != '') 
         THEN NEW.first_name || ' ' || NEW.last_name END,
    -- Fall back to full_name if it exists
    NEW.full_name,
    -- Fall back to just first_name if it exists
    NEW.first_name,
    -- Fall back to just last_name if it exists
    NEW.last_name,
    -- Last resort
    'Unknown Guard'
  );
  
  -- Ensure name fields consistency
  IF (NEW.full_name IS NOT NULL AND NEW.full_name != '') THEN
    IF (NEW.first_name IS NULL OR NEW.first_name = '') THEN
      NEW.first_name := SPLIT_PART(NEW.full_name, ' ', 1);
    END IF;
    
    IF (NEW.last_name IS NULL OR NEW.last_name = '') THEN
      IF (POSITION(' ' IN NEW.full_name) > 0) THEN
        NEW.last_name := SUBSTRING(NEW.full_name FROM POSITION(' ' IN NEW.full_name) + 1);
      ELSE
        NEW.last_name := '';
      END IF;
    END IF;
  END IF;
  
  -- If we have first_name and last_name but no full_name, update full_name
  IF ((NEW.first_name IS NOT NULL AND NEW.first_name != '') OR 
      (NEW.last_name IS NOT NULL AND NEW.last_name != '')) AND
     (NEW.full_name IS NULL OR NEW.full_name = '') THEN
    
    NEW.full_name := CONCAT_WS(' ', 
                             CASE WHEN NEW.first_name IS NULL THEN '' ELSE NEW.first_name END,
                             CASE WHEN NEW.last_name IS NULL THEN '' ELSE NEW.last_name END);
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_guard_display_name() OWNER TO postgres;

--
-- Name: update_guard_performance_metrics(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_guard_performance_metrics() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Insert or update performance metrics based on latest reviews
  INSERT INTO guard_performance_metrics (
    guard_id,
    overall_rating,
    punctuality_rating,
    professionalism_rating,
    reliability_rating,
    communication_rating,
    last_review_date,
    next_review_date,
    status
  )
  SELECT 
    NEW.guard_id,
    AVG(overall_rating),
    AVG(punctuality_rating),
    AVG(professionalism_rating),
    AVG(reliability_rating),
    AVG(communication_rating),
    MAX(review_date),
    MAX(follow_up_date),
    CASE 
      WHEN AVG(overall_rating) >= 4.5 THEN 'excellent'::performance_status
      WHEN AVG(overall_rating) >= 4.0 THEN 'good'::performance_status
      WHEN AVG(overall_rating) >= 3.5 THEN 'satisfactory'::performance_status
      WHEN AVG(overall_rating) >= 2.5 THEN 'needs_improvement'::performance_status
      ELSE 'poor'::performance_status
    END
  FROM guard_performance_reviews 
  WHERE guard_id = NEW.guard_id AND status = 'completed'
  ON CONFLICT (guard_id) 
  DO UPDATE SET
    overall_rating = EXCLUDED.overall_rating,
    punctuality_rating = EXCLUDED.punctuality_rating,
    professionalism_rating = EXCLUDED.professionalism_rating,
    reliability_rating = EXCLUDED.reliability_rating,
    communication_rating = EXCLUDED.communication_rating,
    last_review_date = EXCLUDED.last_review_date,
    next_review_date = EXCLUDED.next_review_date,
    status = EXCLUDED.status,
    updated_at = NOW();

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_guard_performance_metrics() OWNER TO postgres;

