--
-- Name: activity_statistics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.activity_statistics AS
 SELECT count(*) AS total_activities,
    count(*) FILTER (WHERE (date(activity_logs."timestamp") = CURRENT_DATE)) AS today_activities,
    count(*) FILTER (WHERE ((activity_logs.status)::text = 'failed'::text)) AS failed_activities,
    count(*) FILTER (WHERE ((activity_logs.severity)::text = 'critical'::text)) AS critical_activities,
    count(*) FILTER (WHERE (activity_logs."timestamp" > (now() - '7 days'::interval))) AS last_7_days,
    count(*) FILTER (WHERE (activity_logs."timestamp" > (now() - '30 days'::interval))) AS last_30_days,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'login'::text)) AS login_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'logout'::text)) AS logout_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'create'::text)) AS create_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'update'::text)) AS update_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'delete'::text)) AS delete_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'view'::text)) AS view_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'export'::text)) AS export_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'security'::text)) AS security_count,
    count(*) FILTER (WHERE ((activity_logs.action_type)::text = 'system'::text)) AS system_count,
    count(*) FILTER (WHERE ((activity_logs.status)::text = 'success'::text)) AS success_count,
    count(*) FILTER (WHERE ((activity_logs.status)::text = 'failed'::text)) AS failed_count,
    count(*) FILTER (WHERE ((activity_logs.status)::text = 'warning'::text)) AS warning_count
   FROM public.activity_logs;


ALTER TABLE public.activity_statistics OWNER TO postgres;

