--
-- Name: admin_join_request_notifications; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.admin_join_request_notifications AS
 SELECT jr.id AS request_id,
    jr.created_at AS request_date,
    jr.status AS request_status,
    jr.is_manual_entry,
    ((u.first_name || ' '::text) || u.last_name) AS user_name,
    u.email AS user_email,
    u.phone AS user_phone,
        CASE
            WHEN jr.is_manual_entry THEN jr.community_name
            ELSE s.name
        END AS community_name,
        CASE
            WHEN jr.is_manual_entry THEN jr.manual_unit_info
            ELSE ((units.block || '-'::text) || units.number)
        END AS unit_info,
    jr.comments,
    count(n.id) AS in_app_notifications_sent,
    count(eq.id) AS emails_queued,
    count(sq.id) AS sms_queued,
    count(
        CASE
            WHEN (eq.status = 'sent'::text) THEN 1
            ELSE NULL::integer
        END) AS emails_sent,
    count(
        CASE
            WHEN (eq.status = 'failed'::text) THEN 1
            ELSE NULL::integer
        END) AS emails_failed,
    count(
        CASE
            WHEN (sq.status = 'sent'::text) THEN 1
            ELSE NULL::integer
        END) AS sms_sent,
    count(
        CASE
            WHEN (sq.status = 'failed'::text) THEN 1
            ELSE NULL::integer
        END) AS sms_failed
   FROM ((((((public.join_requests jr
     JOIN public.users u ON ((jr.user_id = u.id)))
     LEFT JOIN public.communities s ON ((jr.community_id = s.id)))
     LEFT JOIN public.units ON ((jr.unit_id = units.id)))
     LEFT JOIN public.notifications n ON ((jr.id = n.reference_id)))
     LEFT JOIN public.join_request_email_queue eq ON ((jr.id = eq.join_request_id)))
     LEFT JOIN public.join_request_sms_queue sq ON ((jr.id = sq.join_request_id)))
  GROUP BY jr.id, jr.created_at, jr.status, jr.is_manual_entry, u.first_name, u.last_name, u.email, u.phone, jr.community_name, s.name, jr.manual_unit_info, units.block, units.number, jr.comments
  ORDER BY jr.created_at DESC;


ALTER TABLE public.admin_join_request_notifications OWNER TO postgres;

