    CONSTRAINT user_groups_max_members_check CHECK ((max_members > 0)),
    CONSTRAINT user_groups_member_count_check CHECK ((member_count >= 0)),
    CONSTRAINT user_groups_type_check CHECK (((type)::text = ANY ((ARRAY['block'::character varying, 'role'::character varying, 'interest'::character varying, 'committee'::character varying, 'custom'::character varying])::text[])))
);


