--
-- Name: group_statistics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.group_statistics AS
 SELECT count(*) AS total_groups,
    count(*) FILTER (WHERE (subquery.is_active = true)) AS active_groups,
    sum(subquery.member_count) AS total_members,
    round(avg(subquery.member_count)) AS avg_members_per_group,
    jsonb_object_agg(subquery.type, subquery.type_count) AS groups_by_type
   FROM ( SELECT user_groups.type,
            count(*) AS type_count,
            user_groups.is_active,
            user_groups.member_count
           FROM public.user_groups
          GROUP BY user_groups.type, user_groups.is_active, user_groups.member_count) subquery;


