--
-- Name: groups_with_leaders; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.groups_with_leaders AS
 SELECT g.id,
    g.name,
    g.description,
    g.color,
    g.type,
    g.member_count,
    g.max_members,
    g.is_active,
    g.auto_assign,
    g.assignment_rules,
    g.leader_id,
    g.tags,
    g.created_at,
    g.updated_at,
    g.created_by,
    g.updated_by,
    u.email AS leader_email,
    COALESCE(((p.first_name || ' '::text) || p.last_name), (u.email)::text) AS leader_name
   FROM ((public.user_groups g
     LEFT JOIN auth.users u ON ((g.leader_id = u.id)))
     LEFT JOIN public.profiles p ON ((g.leader_id = p.id)));


ALTER TABLE public.groups_with_leaders OWNER TO postgres;

