    emergency_contact character varying(20),
    employment_date date,
    salary numeric(10,2),
    is_active boolean DEFAULT true,
    community_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    email character varying(255),
    phone character varying(20),
    date_of_birth date,
    avatar_url text,
    unit_id uuid,
    role character varying(50) DEFAULT 'GUARD'::character varying,
    first_name character varying,
    last_name character varying,
    display_name character varying,
    emergency_contact_name character varying,
    status character varying DEFAULT 'active'::character varying,
    address character varying,
    blood_group character varying,
    medical_conditions text,
    certifications jsonb DEFAULT '[]'::jsonb,
    experience integer DEFAULT 0,
    rating numeric DEFAULT 0,
    total_shifts integer DEFAULT 0,
    completed_shifts integer DEFAULT 0,
    skills jsonb DEFAULT '[]'::jsonb,
    mobile text,
    shift_start_time time without time zone,
    shift_end_time time without time zone,
    gate_assignment text,
    emergency_contact_phone text,
    experience_years integer DEFAULT 0,
    community_assignment text,
    last_login timestamp with time zone,
    CONSTRAINT guards_blood_group_check CHECK ((((blood_group)::text = ANY ((ARRAY['A+'::character varying, 'A-'::character varying, 'B+'::character varying, 'B-'::character varying, 'AB+'::character varying, 'AB-'::character varying, 'O+'::character varying, 'O-'::character varying])::text[])) OR (blood_group IS NULL))),
    CONSTRAINT guards_shift_type_check CHECK (((shift_type)::text = ANY ((ARRAY['day'::character varying, 'night'::character varying, 'rotating'::character varying, 'flexible'::character varying])::text[]))),
    CONSTRAINT guards_status_check CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'inactive'::character varying, 'suspended'::character varying, 'on_leave'::character varying, 'terminated'::character varying])::text[])))
);


ALTER TABLE public.guards OWNER TO postgres;

