-- Name: TABLE guards; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.guards IS 'Security guards assigned to societies';


--
-- Name: guard_performance_detailed; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.guard_performance_detailed AS
 SELECT gpm.id,
    gpm.guard_id,
    gpm.overall_rating,
    gpm.punctuality_rating,
    gpm.professionalism_rating,
    gpm.reliability_rating,
    gpm.communication_rating,
    gpm.attendance_percentage,
    gpm.total_shifts,
    gpm.completed_shifts,
    gpm.late_arrivals,
    gpm.incident_reports,
    gpm.compliments,
    gpm.complaints,
    gpm.last_review_date,
    gpm.next_review_date,
    gpm.status,
    gpm.monthly_progress,
    gpm.created_at,
    gpm.updated_at,
    COALESCE(NULLIF(g.full_name, ''::text), NULLIF(TRIM(BOTH FROM concat_ws(' '::text, g.first_name, g.last_name)), ''::text), NULLIF(TRIM(BOTH FROM concat_ws(' '::text, p.first_name, p.last_name)), ''::text)) AS guard_name,
    COALESCE(g.avatar_url, p.avatar_url) AS avatar_url,
    g.employee_id,
    g.shift_type,
    g.employment_date
   FROM ((public.guard_performance_metrics gpm
     LEFT JOIN public.guards g ON ((g.id = gpm.guard_id)))
     LEFT JOIN LATERAL ( SELECT p_1.first_name,
            p_1.last_name,
            p_1.avatar_url
           FROM public.profiles p_1
          WHERE ((g.user_id IS NOT NULL) AND ((p_1.user_id = g.user_id) OR (p_1.id = g.user_id)))
          ORDER BY (CASE
                        WHEN (p_1.user_id = g.user_id) THEN 0
                        ELSE 1
                    END), p_1.id
         LIMIT 1) p ON (true));


ALTER TABLE public.guard_performance_detailed OWNER TO postgres;

