CREATE TABLE public.guard_performance_reviews (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    guard_id uuid NOT NULL,
    reviewer_id uuid,
    review_date date DEFAULT CURRENT_DATE NOT NULL,
    overall_rating numeric(2,1) NOT NULL,
    punctuality_rating numeric(2,1) NOT NULL,
    professionalism_rating numeric(2,1) NOT NULL,
    reliability_rating numeric(2,1) NOT NULL,
    communication_rating numeric(2,1) NOT NULL,
    strengths text NOT NULL,
    areas_for_improvement text NOT NULL,
    goals text,
    comments text,
    action_plan text,
    follow_up_date date,
    status public.review_status DEFAULT 'draft'::public.review_status NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT guard_performance_reviews_communication_rating_check CHECK (((communication_rating >= (1)::numeric) AND (communication_rating <= (5)::numeric))),
    CONSTRAINT guard_performance_reviews_overall_rating_check CHECK (((overall_rating >= (1)::numeric) AND (overall_rating <= (5)::numeric))),
    CONSTRAINT guard_performance_reviews_professionalism_rating_check CHECK (((professionalism_rating >= (1)::numeric) AND (professionalism_rating <= (5)::numeric))),
    CONSTRAINT guard_performance_reviews_punctuality_rating_check CHECK (((punctuality_rating >= (1)::numeric) AND (punctuality_rating <= (5)::numeric))),
    CONSTRAINT guard_performance_reviews_reliability_rating_check CHECK (((reliability_rating >= (1)::numeric) AND (reliability_rating <= (5)::numeric))),
    CONSTRAINT valid_follow_up_date CHECK (((follow_up_date IS NULL) OR (follow_up_date >= review_date)))
);


ALTER TABLE public.guard_performance_reviews OWNER TO postgres;

