-- Name: TABLE guard_performance_reviews; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.guard_performance_reviews IS 'Stores individual performance review records for guards';


--
-- Name: COLUMN guard_performance_reviews.overall_rating; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.guard_performance_reviews.overall_rating IS 'Overall performance rating (1-5 scale)';


--
-- Name: guard_performance_reviews_detailed; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.guard_performance_reviews_detailed AS
 SELECT gpr.id,
    gpr.guard_id,
    gpr.reviewer_id,
    gpr.review_date,
    gpr.overall_rating,
    gpr.punctuality_rating,
    gpr.professionalism_rating,
    gpr.reliability_rating,
    gpr.communication_rating,
    gpr.strengths,
    gpr.areas_for_improvement,
    gpr.goals,
    gpr.comments,
    gpr.action_plan,
    gpr.follow_up_date,
    gpr.status,
    gpr.created_at,
    gpr.updated_at,
    COALESCE(NULLIF(g.full_name, ''::text), NULLIF(TRIM(BOTH FROM concat_ws(' '::text, g.first_name, g.last_name)), ''::text), NULLIF(TRIM(BOTH FROM concat_ws(' '::text, gp.first_name, gp.last_name)), ''::text)) AS guard_name,
    NULLIF(TRIM(BOTH FROM concat_ws(' '::text, rp.first_name, rp.last_name)), ''::text) AS reviewer_name
   FROM (((public.guard_performance_reviews gpr
     LEFT JOIN public.guards g ON ((g.id = gpr.guard_id)))
     LEFT JOIN LATERAL ( SELECT p.first_name,
            p.last_name
           FROM public.profiles p
          WHERE ((g.user_id IS NOT NULL) AND ((p.user_id = g.user_id) OR (p.id = g.user_id)))
          ORDER BY (CASE
                        WHEN (p.user_id = g.user_id) THEN 0
                        ELSE 1
                    END), p.id
         LIMIT 1) gp ON (true))
     LEFT JOIN public.profiles rp ON ((rp.id = gpr.reviewer_id)));


ALTER TABLE public.guard_performance_reviews_detailed OWNER TO postgres;

