--
-- Name: TABLE role_permissions; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE public.role_permissions IS 'Junction table linking roles to permissions';


--
-- Name: permissions_with_role_count; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.permissions_with_role_count AS
 SELECT p.id,
    p.name,
    p.key,
    p.description,
    p.category,
    p.module,
    p.type,
    p.is_system_permission,
    p.status,
    p.created_at,
    p.updated_at,
    p.created_by,
    p.updated_by,
    COALESCE(rp.role_count, (0)::bigint) AS role_count
   FROM (public.permissions p
     LEFT JOIN ( SELECT role_permissions.permission_id,
            count(*) AS role_count
           FROM public.role_permissions
          GROUP BY role_permissions.permission_id) rp ON ((p.id = rp.permission_id)));


ALTER TABLE public.permissions_with_role_count OWNER TO postgres;

