--
-- Name: recent_activities; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.recent_activities AS
 SELECT al.id,
    al.user_id,
    al.user_name,
    al.user_role,
    al.action,
    al.action_type,
    al.resource,
    al.resource_id,
    al.details,
    al.ip_address,
    al.user_agent,
    al.location,
    al.status,
    al.severity,
    al.metadata,
    al."timestamp",
    al.created_at,
        CASE
            WHEN (al."timestamp" > (now() - '00:01:00'::interval)) THEN 'Just now'::text
            WHEN (al."timestamp" > (now() - '01:00:00'::interval)) THEN ((EXTRACT(epoch FROM (now() - al."timestamp")) / (60)::numeric) || 'm ago'::text)
            WHEN (al."timestamp" > (now() - '1 day'::interval)) THEN ((EXTRACT(epoch FROM (now() - al."timestamp")) / (3600)::numeric) || 'h ago'::text)
            ELSE ((EXTRACT(epoch FROM (now() - al."timestamp")) / (86400)::numeric) || 'd ago'::text)
        END AS relative_time,
    p.first_name,
    p.last_name,
    p.email
   FROM (public.activity_logs al
     LEFT JOIN public.profiles p ON ((al.user_id = p.id)))
  WHERE (al."timestamp" > (now() - '30 days'::interval))
  ORDER BY al."timestamp" DESC;


