--
-- Name: security_events; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.security_events AS
 SELECT activity_logs.id,
    activity_logs.user_id,
    activity_logs.user_name,
    activity_logs.user_role,
    activity_logs.action,
    activity_logs.action_type,
    activity_logs.resource,
    activity_logs.resource_id,
    activity_logs.details,
    activity_logs.ip_address,
    activity_logs.user_agent,
    activity_logs.location,
    activity_logs.status,
    activity_logs.severity,
    activity_logs.metadata,
    activity_logs."timestamp",
    activity_logs.created_at
   FROM public.activity_logs
  WHERE (((activity_logs.action_type)::text = 'security'::text) OR ((activity_logs.status)::text = 'failed'::text) OR ((activity_logs.severity)::text = ANY ((ARRAY['high'::character varying, 'critical'::character varying])::text[])))
  ORDER BY activity_logs."timestamp" DESC;


