--
-- Name: sms_analytics; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.sms_analytics (
    id text DEFAULT (gen_random_uuid())::text NOT NULL,
    metric_date date NOT NULL,
    total_sent integer DEFAULT 0,
    total_delivered integer DEFAULT 0,
    total_failed integer DEFAULT 0,
    total_responses integer DEFAULT 0,
    total_cost numeric(10,2) DEFAULT 0,
    credits_used integer DEFAULT 0,
    delivery_rate numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (total_sent > 0) THEN (((total_delivered)::numeric / (total_sent)::numeric) * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    response_rate numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (total_delivered > 0) THEN (((total_responses)::numeric / (total_delivered)::numeric) * (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


