--
-- Name: users_with_preference_stats; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.users_with_preference_stats AS
 SELECT u.id,
    u.email,
    p.full_name AS user_name,
    p.role AS user_role,
    count(upv.id) AS customizations,
    max(upv.updated_at) AS last_updated
   FROM ((auth.users u
     JOIN public.profiles p ON ((u.id = p.id)))
     LEFT JOIN public.user_preference_values upv ON ((u.id = upv.user_id)))
  GROUP BY u.id, u.email, p.full_name, p.role;


ALTER TABLE public.users_with_preference_stats OWNER TO postgres;

--
-- Name: VIEW users_with_preference_stats; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.users_with_preference_stats IS 'Security fix 2026-02-05: Revoked anon access. Only authenticated users can access.';


