--
-- Name: preference_settings_with_stats _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.preference_settings_with_stats AS
 SELECT ps.id,
    ps.category_id,
    ps.key,
    ps.name,
    ps.description,
    ps.type,
    ps.default_value,
    ps.options,
    ps.validation,
    ps.is_user_editable,
    ps.is_system_setting,
    ps.created_at,
    ps.updated_at,
    count(upv.id) AS affected_users
   FROM (public.preference_settings ps
     LEFT JOIN public.user_preference_values upv ON ((ps.id = upv.preference_id)))
  GROUP BY ps.id;


