--
-- Name: maintenance_comments maintenance_comments_delete_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY maintenance_comments_delete_policy ON public.maintenance_comments FOR DELETE TO authenticated USING (((auth.uid() IS NULL) OR (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.id = maintenance_comments.created_by) AND (p.user_id = auth.uid())))) OR (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.user_id = auth.uid()) AND (p.role = 'admin'::text))))));


--
-- Name: maintenance_comments maintenance_comments_insert_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY maintenance_comments_insert_policy ON public.maintenance_comments FOR INSERT TO authenticated WITH CHECK (((auth.uid() IS NULL) OR ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.id = maintenance_comments.created_by) AND (p.user_id = auth.uid())))) AND (EXISTS ( SELECT 1
   FROM (public.maintenance_requests mr
     JOIN public.profiles user_profile ON ((user_profile.user_id = auth.uid())))
  WHERE ((mr.id = maintenance_comments.maintenance_id) AND ((mr.requested_by = user_profile.id) OR (mr.assigned_to = user_profile.id) OR (user_profile.role = 'admin'::text))))))));


--
-- Name: maintenance_comments maintenance_comments_select_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY maintenance_comments_select_policy ON public.maintenance_comments FOR SELECT TO authenticated USING (((auth.uid() IS NULL) OR (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.id = maintenance_comments.created_by) AND (p.user_id = auth.uid())))) OR (EXISTS ( SELECT 1
   FROM (public.maintenance_requests mr
     JOIN public.profiles user_profile ON ((user_profile.user_id = auth.uid())))
  WHERE ((mr.id = maintenance_comments.maintenance_id) AND ((mr.requested_by = user_profile.id) OR (mr.assigned_to = user_profile.id) OR (user_profile.role = 'admin'::text)))))));


--
-- Name: maintenance_comments maintenance_comments_update_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY maintenance_comments_update_policy ON public.maintenance_comments FOR UPDATE TO authenticated USING (((auth.uid() IS NULL) OR (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.id = maintenance_comments.created_by) AND (p.user_id = auth.uid())))))) WITH CHECK (((auth.uid() IS NULL) OR (EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE ((p.id = maintenance_comments.created_by) AND (p.user_id = auth.uid()))))));


