ALTER TABLE public.system_performance ENABLE ROW LEVEL SECURITY;

--
-- Name: system_performance system_performance_admin_read; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY system_performance_admin_read ON public.system_performance FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM public.profiles p
  WHERE (((p.id = auth.uid()) OR (p.user_id = auth.uid())) AND (p.role = ANY (ARRAY['superadmin'::text, 'admin'::text, 'agency_manager'::text, 'facility_manager'::text]))))));


