-- Name: user_roles user_roles_write_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY user_roles_write_policy ON public.user_roles TO authenticated USING ((EXISTS ( SELECT 1
   FROM (public.profiles p
     JOIN public.user_roles ur ON ((p.role_id = ur.id)))
  WHERE ((p.id = auth.uid()) AND ((ur.permissions @> '["all"]'::jsonb) OR (ur.permissions @> '["user_management"]'::jsonb))))));


